// Extract plain text from email
// Support both field naming conventions (textHtml/textPlain and html/text)
const data = $input.first().json;
let text = '';
const html = data.textHtml || data.html || '';
const textBody = data.textPlain || data.text || '';

// Fix encoding: GMX sometimes delivers UTF-8 bytes misread as Latin-1
function fixEncoding(str) {
  if (!str) return '';
  return str
    .replace(/Ã¤/g, 'ä').replace(/Ã/g, 'Ä')
    .replace(/Ã¶/g, 'ö').replace(/Ã/g, 'Ö')
    .replace(/Ã¼/g, 'ü').replace(/Ã/g, 'Ü')
    .replace(/Ã/g, 'ß')
    .replace(/â/g, '—').replace(/â/g, '–')
    .replace(/â/g, "'").replace(/â/g, "'")
    .replace(/â/g, '„').replace(/â/g, '“')
    .replace(/â¦/g, '…');
}

if (textBody && textBody.trim().length > 0) {
  text = fixEncoding(textBody);
} else if (html) {
  text = fixEncoding(
    html
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/p>/gi, '\n\n')
      .replace(/<\/div>/gi, '\n')
      .replace(/<\/li>/gi, '\n')
      .replace(/<[^>]+>/g, '')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&auml;/g, 'ä').replace(/&Auml;/g, 'Ä')
      .replace(/&ouml;/g, 'ö').replace(/&Ouml;/g, 'Ö')
      .replace(/&uuml;/g, 'ü').replace(/&Uuml;/g, 'Ü')
      .replace(/&szlig;/g, 'ß')
      .replace(/&mdash;/g, '—').replace(/&ndash;/g, '–')
      .replace(/&#\d+;/g, '')
      .replace(/\n{3,}/g, '\n\n')
      .trim()
  );
}

const subject = fixEncoding(data.subject || 'Kein Betreff');
const date = data.date;
const from = data.from;

const mailDate = new Date(date);
const dateStr = mailDate.toISOString().split('T')[0];

const slug = subject
  .toLowerCase()
  .replace(/[äÄ]/g, 'ae')
  .replace(/[öÖ]/g, 'oe')
  .replace(/[üÜ]/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 40);

return {
  json: {
    text,
    subject,
    date: dateStr,
    from,
    slug,
    branchName: `aktuelles/${"${dateStr}"}-${"${slug}"}`
  }
};

// Parse AI Agent response - extract JSON from output
const response = $input.first().json;
const output = response.output || response.text || '';

// Extract JSON from response (might be wrapped in markdown code block)
let jsonStr = output;
const jsonMatch = output.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) {
  jsonStr = jsonMatch[1].trim();
} else {
  const objMatch = output.match(/(\{[\s\S]*\})/);
  if (objMatch) {
    jsonStr = objMatch[1];
  }
}

let items = [];
try {
  const parsed = JSON.parse(jsonStr);
  items = parsed.items || [];
} catch (e) {
  // If JSON parsing fails, continue with empty items
  items = [];
}

const mailDate = $('Text extrahieren').first().json.date;
const branchName = $('Text extrahieren').first().json.branchName;
const subject = $('Text extrahieren').first().json.subject;

const beitraege = items.filter(i => i.type === 'beitrag');
const quickinfos = items.filter(i => i.type === 'quickinfo');
const termine = items.filter(i => i.type === 'termin');

const files = [];

for (const item of [...beitraege, ...quickinfos]) {
  const frontmatter = [
    '---',
    `title: "${item.title}"`,
    `date: ${mailDate}`,
    `description: "${item.description || ''}"`,
    `tags: [${(item.tags || []).map(t => `"${t}"`).join(', ')}]`
  ];
  if (item.type === 'quickinfo') {
    frontmatter.push('quickinfo: true');
  }
  frontmatter.push('---');
  frontmatter.push('');
  frontmatter.push(item.body || '');
  frontmatter.push('');

  files.push({
    path: `content/aktuelles/${mailDate}-${item.slug}.md`,
    content: frontmatter.join('\n'),
    type: item.type,
    title: item.title
  });
}

let prBody = '## Neue Inhalte\n\n';
prBody += '| Typ | Datei | Titel |\n|-----|-------|-------|\n';
for (const f of files) {
  prBody += `| ${f.type} | \`${f.path}\` | ${f.title} |\n`;
}
for (const t of termine) {
  prBody += `| termin | \`content/termine/_index.md\` | ${t.title} |\n`;
}
prBody += '\n---\nAutomatisch erstellt aus Mail vom ' + mailDate;

return {
  json: {
    files,
    termine,
    branchName,
    mailDate,
    subject,
    prBody,
    stats: {
      beitraege: beitraege.length,
      quickinfos: quickinfos.length,
      termine: termine.length
    }
  }
};

// Get existing termine file content and merge with new termine
const termineFile = $('Termine laden').first().json;
const existingContent = Buffer.from(termineFile.content, 'base64').toString('utf-8');
const existingSha = termineFile.sha;

const parsed = $('Antwort verarbeiten').first().json;
const newTermine = parsed.termine;
const files = parsed.files;
const branchName = parsed.branchName;

// Parse existing YAML events from frontmatter
const frontmatterMatch = existingContent.match(/^---\n([\s\S]*?)\n---/);
let yamlContent = frontmatterMatch ? frontmatterMatch[1] : '';

// Simple duplicate check: extract existing event dates+titles
const existingEvents = [];
const eventRegex = /- title: "([^"]*)"|  date: (\d{4}-\d{2}-\d{2})/g;
let match;
let currentTitle = '';
while ((match = eventRegex.exec(yamlContent)) !== null) {
  if (match[1]) currentTitle = match[1];
  if (match[2]) existingEvents.push({ title: currentTitle.toLowerCase(), date: match[2] });
}

// Filter out duplicate termine
const uniqueTermine = newTermine.filter(t => {
  const isDuplicate = existingEvents.some(e =>
    e.date === t.date &&
    (e.title.includes(t.title.toLowerCase().substring(0, 10)) ||
     t.title.toLowerCase().includes(e.title.substring(0, 10)))
  );
  return !isDuplicate;
});

// Append new termine to YAML
let updatedContent = existingContent;
if (uniqueTermine.length > 0) {
  const closingIndex = existingContent.lastIndexOf('---');
  let newYaml = '';
  for (const t of uniqueTermine) {
    newYaml += `  - title: "${t.title}"\n`;
    newYaml += `    date: ${t.date}\n`;
    if (t.time) newYaml += `    time: "${t.time}"\n`;
    if (t.detail) newYaml += `    detail: "${t.detail}"\n`;
    newYaml += `    category: "${t.category || 'event'}"\n`;
  }
  updatedContent = existingContent.substring(0, closingIndex) + newYaml + '---';
}

return {
  json: {
    files,
    branchName,
    mailDate: parsed.mailDate,
    subject: parsed.subject,
    prBody: parsed.prBody,
    stats: parsed.stats,
    termineContent: updatedContent,
    termineSha: existingSha,
    hasNewTermine: uniqueTermine.length > 0,
    skippedTermine: newTermine.length - uniqueTermine.length
  }
};

// Create all GitHub file creation API calls
const data = $('Termine zusammenfuehren').first().json;
const items = [];

for (const file of data.files) {
  items.push({
    json: {
      path: file.path,
      content: Buffer.from(file.content).toString('base64'),
      message: 'feat(aktuelles): add ' + file.type + ' - ' + file.title,
      branch: data.branchName
    }
  });
}

if (data.hasNewTermine) {
  items.push({
    json: {
      path: 'content/termine/_index.md',
      content: Buffer.from(data.termineContent).toString('base64'),
      message: 'feat(termine): add events from mail',
      branch: data.branchName,
      sha: data.termineSha
    }
  });
}

if (items.length === 0) {
  items.push({ json: { empty: true } });
}

return items;
